const raw = ($json.content || []).find(b => b.type === 'text')?.text || '';

const clean = raw.trim().startsWith('```')
  ? raw.trim().replace(/^```[a-z]*\n?/, '').replace(/\n?```$/, '').trim()
  : raw.trim();

if (!clean || clean.length < 100) {
  throw new Error('Claude returned an unexpectedly short manuscript. Got: ' + clean.slice(0, 200));
}

const wordCount = clean.split(/\s+/).filter(w => w.length > 0).length;
const productId = $('Webhook Trigger').first().json.body.product_id;

return [{ json: { manuscript: clean, wordCount, productId } }];

const productId  = $('Parse Manuscript').item.json.productId;
const wordCount  = $('Parse Manuscript').item.json.wordCount;
const specItems  = $('Fetch Product Spec').all();
const specRaw    = specItems.length > 0 ? specItems[0].json : [];
const product    = Array.isArray(specRaw) ? (specRaw[0] || {}) : specRaw;

const title        = product.name || product.title || 'Ebook';
const description  = product.description || '';
const spec         = product.spec || {};
const chapterCount = spec.chapters
  ? spec.chapters.length
  : (spec.ebook && spec.ebook.chapters ? spec.ebook.chapters.length : 0);

const dateStr = new Date().toLocaleDateString('en-US', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});

const html = '<div style="max-width:600px;margin:0 auto;font-family:Arial,sans-serif;color:#333;">'
  + '<div style="background:#0A0A0A;padding:24px;text-align:center;">'
  + '<span style="color:#C8F53A;font-size:18px;letter-spacing:3px;font-weight:bold;">CIPHER STUDIO</span>'
  + '</div>'
  + '<div style="padding:24px;">'
  + '<h2 style="margin:0 0 4px;font-size:20px;color:#0A0A0A;">Manuscript Complete</h2>'
  + '<p style="color:#888;margin:0 0 20px;font-size:13px;">' + dateStr + '</p>'
  + '<h3 style="margin:0 0 8px;font-size:16px;color:#0A0A0A;">' + title + '</h3>'
  + (description ? '<p style="color:#666;margin:0 0 16px;font-size:14px;">' + description + '</p>' : '')
  + '<table style="width:100%;margin:0 0 20px;">'
  + '<tr><td style="padding:8px 0;font-size:14px;color:#888;">Word count</td>'
  + '<td style="padding:8px 0;font-size:14px;color:#333;font-weight:bold;">' + Number(wordCount).toLocaleString() + '</td></tr>'
  + (chapterCount ? '<tr><td style="padding:8px 0;font-size:14px;color:#888;">Chapters</td><td style="padding:8px 0;font-size:14px;color:#333;">' + chapterCount + '</td></tr>' : '')
  + '<tr><td style="padding:8px 0;font-size:14px;color:#888;">Next step</td><td style="padding:8px 0;font-size:14px;color:#333;">Ebook Designer Agent triggered</td></tr>'
  + '</table>'
  + '<p style="background:#f5f5f0;border-left:3px solid #C8F53A;padding:12px 16px;font-size:13px;color:#555;margin:0;">The Ebook Designer Agent has been triggered. You will receive a follow-up email when the PDF is ready.</p>'
  + '</div>'
  + '<div style="padding:16px 24px;border-top:1px solid #eee;text-align:center;">'
  + '<span style="font-size:11px;color:#aaa;">Cipher Studio LLC &middot; Automated notification</span>'
  + '</div>'
  + '</div>';

return [{ json: {
  subject: 'Manuscript Written: ' + title + ' (' + Number(wordCount).toLocaleString() + ' words)',
  html
} }];
